import React, { useState } from 'react';
import { View, Button, Text } from 'react-native';
import { Authorized, AuthorizationCodeGrant, Token } from 'react-native-oauth2';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';
const redirectUri = 'yourapp://callback';
const authUrl = 'https://your-auth-server.com/auth';
const tokenUrl = 'https://your-auth-server.com/token';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  const handleLogin = async () => {
    try {
      const authCode = await AuthorizationCodeGrant({ 
        clientId,
        redirectUri,
        authorizationUrl: authUrl 
      });

      const tokenResponse = await fetch(tokenUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${authCode}&client_id=${clientId}&client_secret=${clientSecret}&redirect_uri=${redirectUri}`,
      });

      const { access_token } = await tokenResponse.json();
      setAccessToken(access_token);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Button title="Login" onPress={handleLogin} />
      {accessToken && <Text>Access Token: {accessToken}</Text>}
    </View>
  );
};

export default App;